  ('coaching', 'Coaching containers', 'Personal, high-touch spaces that mirror the depth of the work we do together. Pick the rhythm that meets you right now and I will meet you in your inbox or on our call with grounded, miraculous guidance.', 0, true),
  ('custom-meditation', 'Custom creations', 'Tailored rituals crafted only for you. Every word, sound, and energetic transmission is channelled for the desires you share.', 1, true),
  ('meditations', 'Meditations & rituals', 'Instant-access immersions you can begin tonight. Each portal includes deep guidance plus the energetic amplification you asked for.', 2, true),
  ('digital', 'Digital resources', 'Self-paced support you can download instantly and return to anytime you need a reminder of your power.', 3, true),
  ('energy-readings', 'Energy & tarot readings', 'Channeled guidance so you know exactly where your energy stands and how to realign fast.', 4, true)
